import { Injectable } from '@nestjs/common';

@Injectable()
export class LookupsService {
    private countries: any[] = [];
    private devices: any[] = [];
    private institutions: any[] = [];

    constructor() {
        // Initialize with some default data
        this.countries = [{ id: 1, name: 'United States' }, { id: 2, name: 'Canada' }];
        this.devices = [{ id: 1, name: 'Laptop' }, { id: 2, name: 'Smartphone' }];
        this.institutions = [{ id: 1, name: 'University A' }, { id: 2, name: 'College B' }];
    }

    getCountries(): any[] {
        return this.countries;
    }

    getDevices(): any[] {
        return this.devices;
    }

    getInstitutions(): any[] {
        return this.institutions;
    }

    addCountry(country: any): void {
        this.countries.push(country);
    }

    addDevice(device: any): void {
        this.devices.push(device);
    }

    addInstitution(institution: any): void {
        this.institutions.push(institution);
    }
}
